object Solution {

  // Define the maximum value we need to check, accommodating input up to 10^5 plus a small margin.
  private val MAX_SIEVE = 101000 
  private val isPrime = new Array[Boolean](MAX_SIEVE + 1)
  private var sieveInitialized = false

  // Helper to initialize the Sieve of Eratosthenes
  private def initializeSieve(): Unit = {
    if (sieveInitialized) return

    // Initialize all numbers >= 2 as potentially prime
    (2 until MAX_SIEVE + 1).foreach { i => isPrime(i) = true }
    isPrime(0) = false
    isPrime(1) = false

    var p = 2
    while (p * p <= MAX_SIEVE) {
      if (isPrime(p)) {
        var i = p * p
        while (i <= MAX_SIEVE) {
          isPrime(i) = false
          i += p
        }
      }
      p += 1
    }
    sieveInitialized = true
  }

  // Finds the smallest prime number >= n
  private def findNextPrime(n: Long): Long = {
    initializeSieve()
    var current = n.max(2)
    while (current <= MAX_SIEVE) {
      if (isPrime(current.toInt)) {
        return current
      }
      current += 1
    }
    // Should not be reached given problem constraints and sieve size
    throw new IllegalStateException("Search exceeded maximum bounds")
  }

  // Finds the smallest non-prime number >= n. (1 and composites)
  private def findNextNonPrime(n: Long): Long = {
    initializeSieve()
    var current = n
    while (current <= MAX_SIEVE) {
      // Non-prime means either <= 1 or composite (not prime AND > 1)
      if (current <= 1 || !isPrime(current.toInt)) {
        return current
      }
      current += 1
    }
    // Should not be reached given problem constraints and sieve size
    throw new IllegalStateException("Search exceeded maximum bounds")
